// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import {ERC20} from "@openzeppelin/contracts/token/ERC20/ERC20.sol";
import {Ownable} from "@openzeppelin/contracts/access/Ownable.sol";

/// @title MockUSDC
/// @notice 테스트용 USDC 토큰 - 테스트넷에서 자유롭게 민팅 가능
/// @dev 실제 USDC와 동일하게 6 decimals 사용
contract MockUSDC is ERC20, Ownable {
    /// @notice 한 번에 민팅 가능한 최대량 (안전장치)
    uint256 public constant MAX_MINT_AMOUNT = 1_000_000 * 10 ** 6; // 100만 USDC

    /// @notice 사용자별 마지막 민팅 시간 (스팸 방지)
    mapping(address => uint256) public lastMintTime;

    /// @notice 민팅 쿨다운 시간
    uint256 public constant MINT_COOLDOWN = 1 hours;

    /// @notice 민팅 이벤트
    event Minted(address indexed to, uint256 amount);

    constructor() ERC20("Mock USDC", "mUSDC") Ownable(msg.sender) {
        // 배포자에게 초기 물량 지급 (테스트용)
        _mint(msg.sender, 10_000_000 * 10 ** 6); // 1000만 mUSDC
    }

    /// @notice USDC는 6 decimals 사용
    function decimals() public pure override returns (uint8) {
        return 6;
    }

    /// @notice 누구나 테스트 토큰 민팅 가능 (쿨다운 있음)
    /// @param amount 민팅할 양 (6 decimals 기준)
    function mint(uint256 amount) external {
        require(amount > 0, "Amount must be > 0");
        require(amount <= MAX_MINT_AMOUNT, "Exceeds max mint amount");
        require(
            block.timestamp >= lastMintTime[msg.sender] + MINT_COOLDOWN,
            "Mint cooldown not passed"
        );

        lastMintTime[msg.sender] = block.timestamp;
        _mint(msg.sender, amount);

        emit Minted(msg.sender, amount);
    }

    /// @notice 특정 주소에 민팅 (테스트 편의용)
    /// @param to 받을 주소
    /// @param amount 민팅할 양
    function mintTo(address to, uint256 amount) external {
        require(to != address(0), "Cannot mint to zero address");
        require(amount > 0, "Amount must be > 0");
        require(amount <= MAX_MINT_AMOUNT, "Exceeds max mint amount");
        require(
            block.timestamp >= lastMintTime[msg.sender] + MINT_COOLDOWN,
            "Mint cooldown not passed"
        );

        lastMintTime[msg.sender] = block.timestamp;
        _mint(to, amount);

        emit Minted(to, amount);
    }

    /// @notice Owner는 무제한 민팅 가능 (테스트 시나리오용)
    /// @param to 받을 주소
    /// @param amount 민팅할 양
    function ownerMint(address to, uint256 amount) external onlyOwner {
        require(to != address(0), "Cannot mint to zero address");
        _mint(to, amount);
        emit Minted(to, amount);
    }

    /// @notice 테스트용 토큰 소각
    /// @param amount 소각할 양
    function burn(uint256 amount) external {
        _burn(msg.sender, amount);
    }
}

src/ZKLendingPool.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import {IERC20} from "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import {SafeERC20} from "@openzeppelin/contracts/token/ERC20/utils/SafeERC20.sol";
import {ReentrancyGuard} from "@openzeppelin/contracts/utils/ReentrancyGuard.sol";
import {Ownable} from "@openzeppelin/contracts/access/Ownable.sol";

import {IZKVerifier} from "./interfaces/IZKVerifier.sol";
import {ICommitmentRegistry} from "./interfaces/ICommitmentRegistry.sol";

/// @title ZKLendingPool
/// @notice ZK 프라이버시 보호 렌딩 풀 - 담보 금액을 숨기고 대출
/// @dev
/// ╔══════════════════════════════════════════════════════════════════╗
/// ║                    ZK Private Lending Flow                       ║
/// ╠══════════════════════════════════════════════════════════════════╣
/// ║                                                                  ║
/// ║  1. DEPOSIT (예치)                                               ║
/// ║     User → ETH + commitment → Pool                               ║
/// ║     - 실제 ETH는 컨트랙트가 보관                                  ║
/// ║     - commitment = Hash(amount, salt) 만 공개                    ║
/// ║                                                                  ║
/// ║  2. BORROW (대출)                                                ║
/// ║     User → ZK Proof ("담보 충분!") → Pool → USDC                 ║
/// ║     - CollateralProof: 담보 >= threshold 증명                    ║
/// ║     - LTVProof: debt/collateral <= maxLTV 증명                   ║
/// ║     - 실제 담보 금액은 절대 공개 안 됨!                           ║
/// ║                                                                  ║
/// ║  3. REPAY (상환)                                                 ║
/// ║     User → USDC → Pool → Update commitment                       ║
/// ║     - 부채 상환하면 debt commitment 업데이트                      ║
/// ║                                                                  ║
/// ║  4. WITHDRAW (출금)                                              ║
/// ║     User → ZK Proof + nullifier → ETH                            ║
/// ║     - 부채 없으면 담보 회수 가능                                  ║
/// ║                                                                  ║
/// ║  5. LIQUIDATE (청산)                                             ║
/// ║     Liquidator → LiquidationProof → Liquidation                  ║
/// ║     - health_factor < 1 증명하면 청산 가능                        ║
/// ║                                                                  ║
/// ╚══════════════════════════════════════════════════════════════════╝
///
contract ZKLendingPool is ReentrancyGuard, Ownable {
    using SafeERC20 for IERC20;

    // ============ 상수 ============

    /// @notice 최대 LTV (Loan-to-Value) - 75%
    uint256 public constant MAX_LTV = 75;

    /// @notice 청산 임계값 - 80%
    uint256 public constant LIQUIDATION_THRESHOLD = 80;

    /// @notice 청산 보너스 - 5%
    uint256 public constant LIQUIDATION_BONUS = 5;

    /// @notice 기준 단위 (퍼센트 계산용)
    uint256 public constant PERCENTAGE_BASE = 100;

    // ============ 상태 변수 ============

    /// @notice ZK 검증기 컨트랙트
    IZKVerifier public immutable zkVerifier;

    /// @notice 커밋먼트 저장소 컨트랙트
    ICommitmentRegistry public immutable commitmentRegistry;

    /// @notice 대출 토큰 (USDC)
    IERC20 public immutable borrowToken;

    /// @notice ETH/USD 가격 (8 decimals, 예: 2000_00000000 = $2000)
    uint256 public ethPrice;

    /// @notice 풀에 예치된 총 ETH (프라이버시 보호를 위해 개별 금액은 숨김)
    uint256 public totalCollateralETH;

    /// @notice 총 대출 USDC
    uint256 public totalBorrowedUSDC;

    /// @notice 사용자별 예치 여부 (금액은 숨김)
    mapping(address => bool) public hasDeposit;

    /// @notice 사용자별 대출 여부
    mapping(address => bool) public hasBorrow;

    /// @notice 사용자별 대출 금액 (이건 숨기기 어려움 - USDC 전송이 공개되므로)
    /// @dev 향후 개선: 대출 금액도 commitment로 숨기기
    mapping(address => uint256) public borrowedAmount;

    // ============ 이벤트 ============

    event Deposited(address indexed user, bytes32 commitment, uint256 timestamp);
    event Borrowed(address indexed user, uint256 amount, bytes32 debtCommitment, uint256 timestamp);
    event Repaid(address indexed user, uint256 amount, uint256 timestamp);
    event Withdrawn(address indexed user, bytes32 nullifier, uint256 timestamp);
    event Liquidated(
        address indexed user,
        address indexed liquidator,
        uint256 debtRepaid,
        uint256 collateralSeized,
        uint256 timestamp
    );
    event PriceUpdated(uint256 oldPrice, uint256 newPrice);

    // ============ 에러 ============

    error InvalidProof();
    error InsufficientCollateral();
    error ExceedsMaxLTV();
    error NoDeposit();
    error NoBorrow();
    error AlreadyHasDeposit();
    error NotLiquidatable();
    error InsufficientPoolLiquidity();
    error ZeroAmount();
    error InvalidCommitment();
    error ZeroAddress();

    // ============ 생성자 ============

    /// @dev Zero address 체크 포함
    constructor(
        address _zkVerifier,
        address _commitmentRegistry,
        address _borrowToken,
        uint256 _initialEthPrice
    ) Ownable(msg.sender) {
        // Security: Zero address validation
        if (_zkVerifier == address(0)) revert ZeroAddress();
        if (_commitmentRegistry == address(0)) revert ZeroAddress();
        if (_borrowToken == address(0)) revert ZeroAddress();
        if (_initialEthPrice == 0) revert ZeroAmount();

        zkVerifier = IZKVerifier(_zkVerifier);
        commitmentRegistry = ICommitmentRegistry(_commitmentRegistry);
        borrowToken = IERC20(_borrowToken);
        ethPrice = _initialEthPrice;
    }

    // ============ 관리 함수 ============

    /// @notice ETH 가격 업데이트 (실제로는 Chainlink Oracle 사용)
    /// @param newPrice 새 가격 (8 decimals)
    function updatePrice(uint256 newPrice) external onlyOwner {
        uint256 oldPrice = ethPrice;
        ethPrice = newPrice;
        emit PriceUpdated(oldPrice, newPrice);
    }

    /// @notice 풀에 USDC 유동성 공급 (테스트용)
    function supplyLiquidity(uint256 amount) external onlyOwner {
        borrowToken.safeTransferFrom(msg.sender, address(this), amount);
    }

    // ============ 핵심 함수 ============

    /// @notice ETH 담보 예치
    /// @param commitment Poseidon(amount, salt) 해시값
    /// @dev 실제 금액은 commitment에 숨겨짐
    function deposit(bytes32 commitment) external payable nonReentrant {
        if (msg.value == 0) revert ZeroAmount();
        if (hasDeposit[msg.sender]) revert AlreadyHasDeposit();
        if (commitment == bytes32(0)) revert InvalidCommitment();

        // 커밋먼트 등록 (실제 금액은 숨김)
        // Security: msg.sender를 명시적으로 전달 (tx.origin 사용 안 함)
        commitmentRegistry.registerCommitment(
            commitment,
            ICommitmentRegistry.CommitmentType.COLLATERAL,
            msg.sender
        );

        hasDeposit[msg.sender] = true;
        totalCollateralETH += msg.value;

        emit Deposited(msg.sender, commitment, block.timestamp);
    }

    /// @notice USDC 대출
    /// @param amount 대출할 USDC 양 (6 decimals)
    /// @param debtCommitment 부채 commitment
    /// @param collateralProof 담보 충분 증명
    /// @param ltvProof LTV 비율 증명
    /// @param publicInputs ZK 증명의 public inputs
    function borrow(
        uint256 amount,
        bytes32 debtCommitment,
        IZKVerifier.Proof calldata collateralProof,
        IZKVerifier.Proof calldata ltvProof,
        uint256[] calldata publicInputs
    ) external nonReentrant {
        if (amount == 0) revert ZeroAmount();
        if (!hasDeposit[msg.sender]) revert NoDeposit();
        if (borrowToken.balanceOf(address(this)) < amount) revert InsufficientPoolLiquidity();

        // 1. CollateralProof 검증: 담보 >= 필요 담보량
        bool collateralValid = zkVerifier.verify(
            IZKVerifier.ProofType.COLLATERAL,
            collateralProof,
            publicInputs
        );
        if (!collateralValid) revert InvalidProof();

        // 2. LTVProof 검증: debt/collateral <= MAX_LTV
        bool ltvValid = zkVerifier.verify(IZKVerifier.ProofType.LTV, ltvProof, publicInputs);
        if (!ltvValid) revert ExceedsMaxLTV();

        // 3. 부채 commitment 등록
        // Security: msg.sender를 명시적으로 전달 (tx.origin 사용 안 함)
        commitmentRegistry.registerCommitment(
            debtCommitment,
            ICommitmentRegistry.CommitmentType.DEBT,
            msg.sender
        );

        // 4. 상태 업데이트
        hasBorrow[msg.sender] = true;
        borrowedAmount[msg.sender] += amount;
        totalBorrowedUSDC += amount;

        // 5. USDC 전송
        borrowToken.safeTransfer(msg.sender, amount);

        emit Borrowed(msg.sender, amount, debtCommitment, block.timestamp);
    }

    /// @notice USDC 상환
    /// @param amount 상환할 양
    /// @param newDebtCommitment 업데이트된 부채 commitment (0이면 전액 상환)
    /// @param nullifier 기존 commitment 무효화용
    function repay(
        uint256 amount,
        bytes32 newDebtCommitment,
        bytes32 nullifier
    ) external nonReentrant {
        if (amount == 0) revert ZeroAmount();
        if (!hasBorrow[msg.sender]) revert NoBorrow();

        uint256 currentDebt = borrowedAmount[msg.sender];
        uint256 repayAmount = amount > currentDebt ? currentDebt : amount;

        // USDC 받기
        borrowToken.safeTransferFrom(msg.sender, address(this), repayAmount);

        // 상태 업데이트
        borrowedAmount[msg.sender] -= repayAmount;
        totalBorrowedUSDC -= repayAmount;

        // commitment 업데이트
        (bytes32 collateralComm, bytes32 debtComm) = commitmentRegistry.getUserCommitments(
            msg.sender
        );

        if (borrowedAmount[msg.sender] == 0) {
            // 전액 상환: commitment 삭제
            hasBorrow[msg.sender] = false;
            commitmentRegistry.nullifyCommitment(debtComm, nullifier);
        } else {
            // 부분 상환: commitment 업데이트
            commitmentRegistry.updateCommitment(debtComm, newDebtCommitment, nullifier);
        }

        emit Repaid(msg.sender, repayAmount, block.timestamp);
    }

    /// @notice 담보 출금
    /// @param amount 출금할 ETH 양
    /// @param nullifier commitment 무효화용
    /// @param withdrawProof 출금 가능 증명 (부채 없음 또는 충분한 담보 유지)
    /// @param publicInputs 증명의 public inputs
    function withdraw(
        uint256 amount,
        bytes32 nullifier,
        IZKVerifier.Proof calldata withdrawProof,
        uint256[] calldata publicInputs
    ) external nonReentrant {
        if (amount == 0) revert ZeroAmount();
        if (!hasDeposit[msg.sender]) revert NoDeposit();

        // 부채가 있으면 LTV 체크 필요
        if (hasBorrow[msg.sender]) {
            // LTV proof 검증 (출금 후에도 LTV 유지되는지)
            bool valid = zkVerifier.verify(
                IZKVerifier.ProofType.LTV,
                withdrawProof,
                publicInputs
            );
            if (!valid) revert ExceedsMaxLTV();
        }

        // commitment 처리
        (bytes32 collateralComm, ) = commitmentRegistry.getUserCommitments(msg.sender);

        // 전액 출금이면 commitment 삭제, 아니면 업데이트
        // (단순화를 위해 전액 출금만 지원 - 부채 없을 때)
        if (!hasBorrow[msg.sender]) {
            commitmentRegistry.nullifyCommitment(collateralComm, nullifier);
            hasDeposit[msg.sender] = false;
        }

        totalCollateralETH -= amount;

        // ETH 전송
        (bool success, ) = msg.sender.call{value: amount}("");
        require(success, "ETH transfer failed");

        emit Withdrawn(msg.sender, nullifier, block.timestamp);
    }

    /// @notice 청산
    /// @param user 청산 대상 사용자
    /// @param liquidationProof 청산 가능 증명 (health_factor < 1)
    /// @param publicInputs 증명의 public inputs
    function liquidate(
        address user,
        IZKVerifier.Proof calldata liquidationProof,
        uint256[] calldata publicInputs
    ) external nonReentrant {
        if (!hasBorrow[user]) revert NoBorrow();

        // LiquidationProof 검증: health_factor < 1
        bool valid = zkVerifier.verify(
            IZKVerifier.ProofType.LIQUIDATION,
            liquidationProof,
            publicInputs
        );
        if (!valid) revert NotLiquidatable();

        uint256 debtToRepay = borrowedAmount[user];

        // 청산자가 부채 대신 갚기
        borrowToken.safeTransferFrom(msg.sender, address(this), debtToRepay);

        // 담보 계산 (USD 가치 기준 + 청산 보너스)
        // collateralValue = debtToRepay * (100 + LIQUIDATION_BONUS) / 100
        uint256 collateralValueUSD = (debtToRepay * (PERCENTAGE_BASE + LIQUIDATION_BONUS)) /
            PERCENTAGE_BASE;

        // ETH로 변환 (가격은 8 decimals, USDC는 6 decimals)
        // collateralETH = collateralValueUSD * 1e18 / ethPrice * 1e6 / 1e8
        uint256 collateralETH = (collateralValueUSD * 1e20) / ethPrice;

        // 상태 업데이트
        borrowedAmount[user] = 0;
        totalBorrowedUSDC -= debtToRepay;
        hasBorrow[user] = false;

        // commitment 정리
        (, bytes32 debtComm) = commitmentRegistry.getUserCommitments(user);
        bytes32 nullifier = keccak256(abi.encodePacked(user, block.timestamp, "liquidation"));
        commitmentRegistry.nullifyCommitment(debtComm, nullifier);

        // 담보에서 차감
        if (collateralETH > totalCollateralETH) {
            collateralETH = totalCollateralETH;
        }
        totalCollateralETH -= collateralETH;

        // 청산자에게 담보 전송
        (bool success, ) = msg.sender.call{value: collateralETH}("");
        require(success, "ETH transfer failed");

        emit Liquidated(user, msg.sender, debtToRepay, collateralETH, block.timestamp);
    }

    // ============ 조회 함수 ============

    /// @notice 사용자 포지션 조회
    function getUserPosition(
        address user
    )
        external
        view
        returns (
            bool _hasDeposit,
            bool _hasBorrow,
            uint256 _borrowedAmount,
            bytes32 collateralCommitment,
            bytes32 debtCommitment
        )
    {
        (collateralCommitment, debtCommitment) = commitmentRegistry.getUserCommitments(user);
        return (hasDeposit[user], hasBorrow[user], borrowedAmount[user], collateralCommitment, debtCommitment);
    }

    /// @notice 풀 상태 조회
    function getPoolStatus()
        external
        view
        returns (uint256 _totalCollateralETH, uint256 _totalBorrowedUSDC, uint256 availableLiquidity)
    {
        return (totalCollateralETH, totalBorrowedUSDC, borrowToken.balanceOf(address(this)));
    }

    /// @notice ETH 수신 가능
    receive() external payable {}
}

src/ZKVerifier.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import {IZKVerifier} from "./interfaces/IZKVerifier.sol";
import {Ownable} from "@openzeppelin/contracts/access/Ownable.sol";

/// @title ZKVerifier
/// @notice Groth16 증명 검증기 - BN254 곡선 사용
/// @dev EVM 프리컴파일 활용: ecAdd(0x06), ecMul(0x07), ecPairing(0x08)
///
/// == Groth16 검증 공식 ==
/// e(A, B) = e(α, β) · e(L, γ) · e(C, δ)
///
/// 여기서:
/// - A, B, C: proof (증명자가 제출)
/// - α, β, γ, δ: verification key (신뢰 설정에서 생성)
/// - L: public input들의 선형 조합
///
/// == BN254 곡선 파라미터 ==
/// - 소수 필드: p = 21888242871839275222246405745257275088696311157297823662689037894645226208583
/// - 그룹 차수: r = 21888242871839275222246405745257275088548364400416034343698204186575808495617
///
contract ZKVerifier is IZKVerifier, Ownable {
    // ============ 상수 ============

    /// @notice BN254 소수 필드 모듈러스
    uint256 internal constant PRIME_Q =
        21888242871839275222246405745257275088696311157297823662689037894645226208583;

    /// @notice 스칼라 필드 모듈러스 (그룹 차수)
    uint256 internal constant SCALAR_FIELD =
        21888242871839275222246405745257275088548364400416034343698204186575808495617;

    // ============ 상태 변수 ============

    /// @notice 각 증명 타입별 Verification Key
    /// @dev vk[proofType] = [alpha, beta, gamma, delta, ic[0], ic[1], ...]
    mapping(ProofType => uint256[]) public verificationKeys;

    /// @notice VK 해시 (무결성 검증용)
    mapping(ProofType => bytes32) public vkHashes;

    /// @notice VK 설정 여부
    mapping(ProofType => bool) public isVKSet;

    // ============ 이벤트 ============

    event VerificationKeySet(ProofType indexed proofType, bytes32 vkHash);
    event ProofVerified(ProofType indexed proofType, address indexed verifier, bool success);

    // ============ 에러 ============

    error InvalidProof();
    error InvalidPublicInputs();
    error VKNotSet();
    error InvalidVKLength();
    error PointNotOnCurve();
    error PairingFailed();

    // ============ 생성자 ============

    constructor() Ownable(msg.sender) {}

    // ============ VK 설정 (Owner Only) ============

    /// @notice Verification Key 설정
    /// @dev VK 구조: [alpha.x, alpha.y, beta.x1, beta.x2, beta.y1, beta.y2,
    ///               gamma.x1, gamma.x2, gamma.y1, gamma.y2,
    ///               delta.x1, delta.x2, delta.y1, delta.y2,
    ///               ic[0].x, ic[0].y, ic[1].x, ic[1].y, ...]
    /// @param proofType 증명 타입
    /// @param vk Verification Key 배열
    function setVerificationKey(ProofType proofType, uint256[] calldata vk) external onlyOwner {
        // VK 최소 길이: alpha(2) + beta(4) + gamma(4) + delta(4) + ic[0](2) + ic[1](2) = 18
        if (vk.length < 18) revert InvalidVKLength();

        // IC 포인트 개수 = (전체 길이 - 14) / 2
        // public input 개수 = IC 개수 - 1
        uint256 icCount = (vk.length - 14) / 2;
        if (vk.length != 14 + icCount * 2) revert InvalidVKLength();

        verificationKeys[proofType] = vk;
        vkHashes[proofType] = keccak256(abi.encodePacked(vk));
        isVKSet[proofType] = true;

        emit VerificationKeySet(proofType, vkHashes[proofType]);
    }

    // ============ 증명 검증 ============

    /// @notice ZK 증명 검증
    /// @param proofType 증명 타입
    /// @param proof Groth16 증명 (A, B, C 포인트)
    /// @param publicInputs 공개 입력값들
    /// @return 검증 성공 여부
    function verify(
        ProofType proofType,
        Proof calldata proof,
        uint256[] calldata publicInputs
    ) external view override returns (bool) {
        if (!isVKSet[proofType]) revert VKNotSet();

        uint256[] storage vk = verificationKeys[proofType];
        uint256 icCount = (vk.length - 14) / 2;

        // public input 개수 검증
        if (publicInputs.length != icCount - 1) revert InvalidPublicInputs();

        // public input 범위 검증
        for (uint256 i = 0; i < publicInputs.length; i++) {
            if (publicInputs[i] >= SCALAR_FIELD) revert InvalidPublicInputs();
        }

        // 1. L = ic[0] + Σ(publicInput[i] * ic[i+1]) 계산
        uint256[2] memory L = _computeLinearCombination(vk, publicInputs, icCount);

        // 2. Pairing 검증: e(-A, B) * e(α, β) * e(L, γ) * e(C, δ) == 1
        bool success = _verifyPairing(proof, vk, L);

        // Note: emit removed for view compatibility
        // Event emission happens in LendingPool for transparency

        return success;
    }

    /// @notice VK 해시 조회
    function getVerificationKeyHash(ProofType proofType) external view override returns (bytes32) {
        return vkHashes[proofType];
    }

    // ============ 내부 함수 ============

    /// @notice Linear combination 계산: L = ic[0] + Σ(input[i] * ic[i+1])
    function _computeLinearCombination(
        uint256[] storage vk,
        uint256[] calldata inputs,
        uint256 icCount
    ) internal view returns (uint256[2] memory) {
        // L = ic[0]
        uint256[2] memory L;
        L[0] = vk[14]; // ic[0].x
        L[1] = vk[15]; // ic[0].y

        // L += Σ(input[i] * ic[i+1])
        for (uint256 i = 0; i < inputs.length; i++) {
            uint256[2] memory icPoint;
            icPoint[0] = vk[16 + i * 2]; // ic[i+1].x
            icPoint[1] = vk[17 + i * 2]; // ic[i+1].y

            // scalar multiplication: input[i] * ic[i+1]
            uint256[2] memory product = _ecMul(icPoint, inputs[i]);

            // point addition: L += product
            L = _ecAdd(L, product);
        }

        return L;
    }

    /// @notice Pairing 검증
    /// @dev e(-A, B) * e(α, β) * e(L, γ) * e(C, δ) == 1
    function _verifyPairing(
        Proof calldata proof,
        uint256[] storage vk,
        uint256[2] memory L
    ) internal view returns (bool) {
        // 입력 배열 구성 (4개의 pairing)
        uint256[24] memory input;

        // Pairing 1: e(-A, B)
        // -A = (A.x, PRIME_Q - A.y)
        input[0] = proof.a[0];
        input[1] = PRIME_Q - (proof.a[1] % PRIME_Q);
        input[2] = proof.b[0][0];
        input[3] = proof.b[0][1];
        input[4] = proof.b[1][0];
        input[5] = proof.b[1][1];

        // Pairing 2: e(α, β)
        input[6] = vk[0]; // alpha.x
        input[7] = vk[1]; // alpha.y
        input[8] = vk[2]; // beta.x1
        input[9] = vk[3]; // beta.x2
        input[10] = vk[4]; // beta.y1
        input[11] = vk[5]; // beta.y2

        // Pairing 3: e(L, γ)
        input[12] = L[0];
        input[13] = L[1];
        input[14] = vk[6]; // gamma.x1
        input[15] = vk[7]; // gamma.x2
        input[16] = vk[8]; // gamma.y1
        input[17] = vk[9]; // gamma.y2

        // Pairing 4: e(C, δ)
        input[18] = proof.c[0];
        input[19] = proof.c[1];
        input[20] = vk[10]; // delta.x1
        input[21] = vk[11]; // delta.x2
        input[22] = vk[12]; // delta.y1
        input[23] = vk[13]; // delta.y2

        // Pairing precompile 호출 (0x08)
        uint256[1] memory result;
        bool success;

        assembly {
            // staticcall(gas, address, input_offset, input_size, output_offset, output_size)
            success := staticcall(sub(gas(), 2000), 0x08, input, 768, result, 32)
        }

        if (!success) revert PairingFailed();

        return result[0] == 1;
    }

    /// @notice EC Point Addition (precompile 0x06)
    function _ecAdd(
        uint256[2] memory p1,
        uint256[2] memory p2
    ) internal view returns (uint256[2] memory result) {
        uint256[4] memory input;
        input[0] = p1[0];
        input[1] = p1[1];
        input[2] = p2[0];
        input[3] = p2[1];

        bool success;
        assembly {
            success := staticcall(sub(gas(), 2000), 0x06, input, 128, result, 64)
        }
        require(success, "ecAdd failed");
    }

    /// @notice EC Scalar Multiplication (precompile 0x07)
    function _ecMul(
        uint256[2] memory p,
        uint256 s
    ) internal view returns (uint256[2] memory result) {
        uint256[3] memory input;
        input[0] = p[0];
        input[1] = p[1];
        input[2] = s;

        bool success;
        assembly {
            success := staticcall(sub(gas(), 2000), 0x07, input, 96, result, 64)
        }
        require(success, "ecMul failed");
    }
}

